fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let mut prefix_mod = vec![0; n + 1];
    for i in 0..n {
        prefix_mod[i + 1] = (prefix_mod[i] + nums[i]) % k;
    }

    let mut mod_count = vec![0; k as usize];
    for mod_val in prefix_mod {
        mod_count[mod_val as usize] += 1;
    }

    let mut total = 0;
    for i in 0..k {
        if mod_count[i as usize] > 0 {
            total += mod_count[i as usize] * i;
        }
    }

    total
}
